using Microsoft.ML.Data;

namespace ChurnPredictor.Models;

/// <summary>Raw CSV row — Churned is a string ("Yes"/"No") that gets mapped to a bool Label.</summary>
public sealed class ChurnRawInput
{
    [LoadColumn(0)]
    public float Age { get; set; }

    [LoadColumn(1)]
    public float Income { get; set; }

    [LoadColumn(2)]
    public string Region { get; set; } = string.Empty;

    [LoadColumn(3)]
    public float PurchaseHistory { get; set; }

    [LoadColumn(4)]
    public string Churned { get; set; } = string.Empty;
}

/// <summary>Prediction request (no label needed).</summary>
public sealed class ChurnInput
{
    public float Age { get; set; }
    public float Income { get; set; }
    public string Region { get; set; } = string.Empty;
    public float PurchaseHistory { get; set; }
}

public sealed class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool Churned { get; set; }

    public float Probability { get; set; }

    public float Score { get; set; }
}

