var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");

var dataView = mlContext.Data.LoadFromTextFile<ChurnInput>(
    dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" to boolean label
var pipeline = mlContext.Transforms.CustomMapping<ChurnRawInput, ChurnLabelMapped>(
        (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
        contractName: null)
    .Append(mlContext.Transforms.Text.FeaturizeText("RegionEncoded", nameof(ChurnInput.Region)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(ChurnInput.Age),
        nameof(ChurnInput.Income),
        nameof(ChurnInput.PurchaseHistory),
        "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

// Since the dataset is tiny, we train on all data; with a larger dataset use TrainTestSplit
var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2);
var model = pipeline.Fit(split.TrainSet);

// Log evaluation metrics
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions);
Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, " +
                  $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

// Save model to disk and register PredictionEnginePool
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");
mlContext.Model.Save(model, dataView.Schema, modelPath);

builder.Services.AddPredictionEnginePool<ChurnInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict");

app.MapPost("/predict", (PredictionEnginePool<ChurnInput, ChurnPrediction> pool, ChurnInput input) =>
{
    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        willChurn = prediction.Churned,
        probability = prediction.Probability,
        score = prediction.Score
    });
});

app.Run();

