using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;
using ChurnPredictor.Models;

var builder = WebApplication.CreateBuilder(args);

// Train the model at startup
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");

// Load raw CSV data and map "Yes"/"No" → bool Label before building the pipeline
var rawData = mlContext.Data.LoadFromTextFile<ChurnRawInput>(
    dataPath, hasHeader: true, separatorChar: ',');

// Pre-map label so it's not part of the saved model pipeline
var labelMapper = mlContext.Transforms.Conversion.MapValue(
    "Label", new Dictionary<string, bool> { ["Yes"] = true, ["No"] = false },
    inputColumnName: nameof(ChurnRawInput.Churned));
var labeledData = labelMapper.Fit(rawData).Transform(rawData);

// Pipeline: feature engineering + trainer (no label mapping step)
var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(ChurnInput.Age),
        nameof(ChurnInput.Income),
        nameof(ChurnInput.PurchaseHistory),
        "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression());

// With a larger dataset, use: mlContext.Data.TrainTestSplit(labeledData, testFraction: 0.2)
var model = pipeline.Fit(labeledData);

// Log evaluation metrics (on training data — swap to held-out test set with more data)
var predictions = model.Transform(labeledData);
var metrics = mlContext.BinaryClassification.Evaluate(predictions);
Console.WriteLine($"Model trained — AUC: {metrics.AreaUnderRocCurve:F4}, " +
                  $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

// Save model and register thread-safe PredictionEnginePool
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");
mlContext.Model.Save(model, labeledData.Schema, modelPath);

builder.Services.AddPredictionEnginePool<ChurnInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict");

app.MapPost("/predict", (PredictionEnginePool<ChurnInput, ChurnPrediction> pool, ChurnInput input) =>
{
    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        willChurn = prediction.Churned,
        probability = prediction.Probability,
        score = prediction.Score
    });
});

app.Run();

